/bin/zsh -lc "rtk proxy awk '
{
  if (match("'$0, /status=[0-9]+/)) {
    status = substr($0, RSTART + 7, RLENGTH - 7) + 0
    total[FILENAME]++
    if (status == 429 || status == 500 || status == 503) {
      retryable[FILENAME]++
      printf "%s:%d status=%d retryable'"\\n\", FILENAME, FNR, status
    } else if (status >= 400) {
      nonretryable[FILENAME]++
      printf \"%s:%d status=%d non-retryable\\n\", FILENAME, FNR, status
    }
  }
}
END {
  for (file in total)
    printf \"summary %s total=%d retryable=%d non_retryable=%d\\n\", file, total[file], retryable[file] + 0, nonretryable[file] + 0
}' logs/*.log"

