/bin/zsh -lc "rtk awk '
{
  total[FILENAME]++
  if (match("'$0, /status=([0-9]{3})/, m)) {
    s = m[1] + 0
    if (s == 429 || s == 500 || s == 503) retry[FILENAME]++
    else if (s >= 400) non_retry[FILENAME]++
    if (!(status_seen[FILENAME, s]++)) status_vals[FILENAME]=status_vals[FILENAME] sprintf(" %d", s)
  }
}
END {
  for (f in total) {
    printf "%s|total=%d|retryable=%d|non_retryable=%d|statuses=%s'"\\n\", f, total[f], retry[f]+0, non_retry[f]+0, status_vals[f]
  }
}
' logs/shard-a.log logs/shard-b.log logs/shard-c.log logs/shard-d.log logs/shard-e.log logs/shard-f.log | sort"

